var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>왔군.</color>","JPN":"<color=#ff3636>来たか。</color>","ENG":"<color=#ff3636>So you've come.</color>","TWN":"<color=#ff3636>你來了。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"아포리아…….","JPN":"アポリア……","ENG":"Aporia...","TWN":"阿波利亞……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>또다시 이 몸의 앞을 가로막을 셈인가, 인간.</color>","JPN":"<color=#ff3636>また俺の邪魔をするつもりか、人間。</color>","ENG":"<color=#ff3636>Human, you wish to stop me again?</color>","TWN":"<color=#ff3636>你又打算阻擋我嗎，人類。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>재미있군.</color>","JPN":"<color=#ff3636>面白い。</color>","ENG":"<color=#ff3636>Interesting.</color>","TWN":"<color=#ff3636>真是有意思。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>그러고보니 기억이 나는 것 같기도 해.</color>","JPN":"<color=#ff3636>そういえば、微かに記憶がある。</color>","ENG":"<color=#ff3636>Come to think of it, I think I remember you.</color>","TWN":"<color=#ff3636>說起來，我好像想起來了。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>아무래도 너는 이 몸이 인간이었던 때, 이 몸과 아는 사이였던 모양이군.</color>","JPN":"<color=#ff3636>どうやらお前は、俺が人間だった頃に知り合いだったみたいだな。</color>","ENG":"<color=#ff3636>I'm guessing you and I were close when I was still a human.</color>","TWN":"<color=#ff3636>看來在這具軀殼還是人類的時候，我們互相認識。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>몇번이고, 몇번이고 이 몸의 업을 가로막는 이유는 틀림없이 그 사사로운 감정 때문이겠지.</color>","JPN":"<color=#ff3636>何度も何度も俺の仕事の邪魔をしてくるのは、きっとそれによる些細な感情のせいだろう。</color>","ENG":"<color=#ff3636>I'm sure your sentimental feelings are the reason you are trying to stop me time and time again.</color>","TWN":"<color=#ff3636>一次次，一次次妨礙我前進的原因，無疑是那些感情吧。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>그럼, 특별히 장단에 어울려 주도록 할까.</color>","JPN":"<color=#ff3636>では、特別にその茶番に付き合ってやるか。</color>","ENG":"<color=#ff3636>Then, perhaps I will play along this time.</color>","TWN":"<color=#ff3636>那麼，我要特別配合一下你嗎。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"무슨……?","JPN":"何を……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>스스로 이 쐐기를 몸에 찔러 넣어라.</color>","JPN":"<color=#ff3636>自分でこの楔を身体に突き刺せ。</color>","ENG":"<color=#ff3636>Stab this Wedge into your body.</color>","TWN":"<color=#ff3636>你自己把釘子插進身體裡吧。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>평범한 인간이라면, 정신이 붕괴하겠지만 너는 특별하다.</color>","JPN":"<color=#ff3636>普通の人間なら精神が崩壊するが、お前は特別だ。</color>","ENG":"<color=#ff3636>If you were an ordinary human, it would collapse your mind. But you are special.</color>","TWN":"<color=#ff3636>普通的人類會精神崩潰，但你是特別的。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>그대로 네가 가진 CRF를 모조리 소모시키면.</color>","JPN":"<color=#ff3636>そのままお前が持つCRFを消費し尽くせば、</color>","ENG":"<color=#ff3636>Let it consume every last drop of CRF you have.</color>","TWN":"<color=#ff3636>如果讓他消耗掉你所擁有的最後一點CRF，</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>너 역시 신인류가 되어, 이 몸과 업을 함께 할 수 있겠지.</color>","JPN":"<color=#ff3636>お前も新人類となり、俺と共にこの仕事を成していけるだろう。</color>","ENG":"<color=#ff3636>Then, you will become the new humankind, and together we will continue our duty.</color>","TWN":"<color=#ff3636>你也將成為新的人類，與我共創一番事業。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>선택은 너의 몫이다, 인간.</color>","JPN":"<color=#ff3636>お前が選べ、人間。</color>","ENG":"<color=#ff3636>The choice is yours, human.</color>","TWN":"<color=#ff3636>選擇權在你手裡，人類</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>또한 이것이 너에게 베풀 수 있는 마지막 자비다.</color>","JPN":"<color=#ff3636>そしてこれが、お前に施せる最後の慈悲である。</color>","ENG":"<color=#ff3636>Furthermore, this will be the last bit of mercy I will show.</color>","TWN":"<color=#ff3636>這也是我能給予你的最後一次憐憫。</color>"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KARIN_DELTA_NEXT_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"KARIN_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};